"""Shared tile coordinate constants for integration tests.

All coordinates are verified against the actual mbtiles data served by
the tileserver-gl instance under test.
"""

import json
from pathlib import Path

# ---------------------------------------------------------------------------
# Deterministic tile samples (generated by generate_tile_samples.py)
# Used by stress, sustained load, and performance tests.
# ---------------------------------------------------------------------------

_SAMPLES_PATH = Path(__file__).parent / "tile_samples.json"
_SAMPLES = json.loads(_SAMPLES_PATH.read_text())


def tiles_for(source: str, max_zoom: int | None = None) -> list[dict]:
    """Return tile samples for a source, optionally capped at max_zoom."""
    src = _SAMPLES["sources"][source]
    tiles = src["tiles"]
    if max_zoom is not None:
        tiles = [t for t in tiles if t["z"] <= max_zoom]
    return tiles


