# ---------------------------------------------------------------------------
# URL builders
# ---------------------------------------------------------------------------


def rendered_url(style: str, tile: dict, fmt: str = "png", scale: str = "") -> str:
    """Build a rendered tile URL. scale="" for 1x, "@2x" for retina."""
    return f"/styles/{style}/{tile['z']}/{tile['x']}/{tile['y']}{scale}.{fmt}"


def data_url(source: str, tile: dict, fmt: str) -> str:
    """Build a data tile URL."""
    return f"/data/{source}/{tile['z']}/{tile['x']}/{tile['y']}.{fmt}"
